SELECT ct.*
FROM cleaning_tasks ct
LEFT JOIN devices d ON ct.device_id = d.id
WHERE 1=1

    AND ct.device_id = #{deviceId}


    AND (ct.operator_a_id = #{operatorId} OR ct.operator_b_id = #{operatorId})


    AND ct.task_status = #{taskStatus}


    AND ct.planned_start_time >= #{startTime}


    AND ct.planned_start_time <= #{endTime}

ORDER BY ct.planned_start_time DESC
LIMIT #{offset}, #{pageSize}

SELECT COUNT(*)
FROM cleaning_tasks ct
WHERE 1=1

    AND ct.device_id = #{deviceId}


    AND (ct.operator_a_id = #{operatorId} OR ct.operator_b_id = #{operatorId})


    AND ct.task_status = #{taskStatus}


    AND ct.planned_start_time >= #{startTime}


    AND ct.planned_start_time <= #{endTime}

SELECT task_status, COUNT(*) as count FROM cleaning_tasks WHERE 1=1
AND planned_start_time >= #{startTime}
AND planned_start_time <= #{endTime}
GROUP BY task_status

